#!/usr/bin/env python3
"""
Скрипт для создания PNG карточек персонажей (TavernCard) с вашими обложками.
"""

from PIL import Image, PngImagePlugin
import base64
import json
from pathlib import Path

def create_character_card(char_id: str, character_data: dict, output_dir: Path, source_image_path: str = None):
    """
    Создает PNG файл с зашитыми метаданными TavernCard.
    
    Args:
        char_id: ID персонажа (имя файла без расширения)
        character_data: Словарь с данными персонажа
        output_dir: Папка для сохранения
        source_image_path: Путь к исходной картинке (обложке)
    """
    
    # 1. Загружаем изображение или создаем заглушку
    if source_image_path and Path(source_image_path).exists():
        print(f"📸 Используем обложку для {char_id}: {source_image_path}")
        try:
            img = Image.open(source_image_path).convert("RGB")
            # Ресайзим до 512x512 для стандарта (можно убрать, если хотите сохранить оригинал)
            img = img.resize((512, 512), Image.Resampling.LANCZOS)
        except Exception as e:
            print(f"⚠️ Ошибка открытия картинки {source_image_path}: {e}")
            img = Image.new('RGB', (512, 512), color=(128, 128, 128))
    else:
        print(f"⚪ Обложка не найдена, создаем серый квадрат для {char_id}")
        img = Image.new('RGB', (512, 512), color=(128, 128, 128))

    # 2. Подготавливаем данные (TavernCard V2)
    tavern_card = {
        "spec": "chara_card_v2",
        "spec_version": "2.0",
        "data": character_data
    }

    # 3. Кодируем JSON в Base64
    json_str = json.dumps(tavern_card, ensure_ascii=False)
    b64_data = base64.b64encode(json_str.encode('utf-8')).decode('utf-8')

    # 4. Добавляем метаданные в PNG
    metadata = PngImagePlugin.PngInfo()
    metadata.add_text("chara", b64_data)

    # 5. Сохраняем
    output_path = output_dir / f"{char_id}.png"
    img.save(output_path, "PNG", pnginfo=metadata)
    print(f"✅ Карточка создана: {output_path}\n")

